/**
 * Search CDA6 ECU catalog by name, acronym, or protocol.
 * Case-insensitive substring match.
 * @param {string} query
 * @returns {Array} matching ECU entries
 */
export function findCda6Ecu(query) {
  if (!query || typeof query !== 'string') return [];
  const q = query.toLowerCase().trim();
  if (!q) return ECU_CATALOG_CDA6;
  return ECU_CATALOG_CDA6.filter(e => {
    return (
      e.name.toLowerCase().includes(q) ||
      e.acronym.toLowerCase().includes(q) ||
      (e.protocol && e.protocol.toLowerCase().includes(q))
    );
  });
}

/**
 * Get ECU entry by exact acronym (case-insensitive).
 * @param {string} acronym
 * @returns {object|null}
 */
export function getCda6EcuByAcronym(acronym) {
  if (!acronym) return null;
  const q = acronym.toLowerCase();
  return ECU_CATALOG_CDA6.find(e => e.acronym.toLowerCase() === q) || null;
}

